<template>
  <div id="Container">
<!--    博客右侧-->
    <el-container>
      <el-aside>
        <div :class="['search',{'suspension':search.ifSearchSuspension}]">
          <!--          搜索康框-->
          <div class="search-main">
            <input type="text" @input="handInput" v-model="search.searchInput" placeholder="请输入内容">
            <i class="el-icon-search"></i>
            <ul v-if="!!search.searchList.length">
              <li v-for="item in search.searchList"><router-link v-show="item._id" :to="'/article/'+item._id">{{item.title}}</router-link></li>
            </ul>
          </div>
          <!--          标签-->
          <div class="search-article">
            <ul @mouseleave="coverAnimLeaves">
              <li @mouseenter="coverAnimEnter(index)" v-for="(item,index) in getTags" :key="item"><router-link :to="'/blog/'+index">{{item}}</router-link></li>
            </ul>
            <div class="cover" :style="{top:search.coverTop*40 + 'px'}"></div>
          </div>
        </div>
        <!--        热门文章-->
        <div class="hot">
          <h3>热门文章</h3>
          <ul>
            <li v-for="(item,index) in hot" :key="item._id">
              <i>{{index + 1}}</i>
              <router-link :to="'/article/'+item._id">{{item.title}}</router-link>
            </li>
          </ul>
        </div>
        <!--        置顶推荐-->
        <!--<div class="recommend">
          <h3>置顶推荐</h3>
          <ul>
            <li v-if="!!getRecommend.title">
              <i>1</i>
              <a :href="getRecommend._id">{{getRecommend.title}}</a>
            </li>
          </ul>
        </div>-->
        <!--        最近访客-->
        <div class="visitor">
          <h3>最近访客</h3>
          <ul>
            <li v-for="(item,index) in visitor" :key="item._id" :style="{backgroundImage:'url('+ item.user.photo +')'}">
              <p>{{item.user.user}}</p>
            </li>
          </ul>
        </div>
      </el-aside>
      <!--        文章-->
      <el-main>
        <ArticleShow></ArticleShow>
      </el-main>
    </el-container>
  </div>
</template>

<script>
  //axios
  import axiosApi from '../api/index'
  let getArticleInfo = axiosApi.getArticleInfo;//获取文章标签
  let getArticlePopular = axiosApi.getArticlePopular,
      getSearch = axiosApi.getSearch,//搜索文章
      getVisitor = axiosApi.getVisitor;//获取最近访客列表
  //组件
  import ArticleShow from "./ArticleShow";

  export default {
    name: "Container",
    components:{
      ArticleShow
    },
    data(){
      return{
        // 搜索框
        search:{
          searchInput:"",
          searchList:[],//搜素出来的列表
          t:null,//搜索框的节流
      //文章分类["全部文章","个人日记","Html5&Css3","JavaScript","Node.js","Vue&React","其他"]
          tags:[],
          //coverTop的值
          coverTop:this.$route.params.id -0,
          //滚动一定高度
          ifSearchSuspension:false
        },
        //热门文章
        hot:[],
        /*假设 这是最近访客的数据*/
        visitor: []
      }
    },
    computed:{
      getTags(){
        return ["全部文章",...this.search.tags]
      },
      /*getRecommend(){
        return this.hot[0] || {}
      }*/
    },
    methods:{
      coverAnimLeaves(){
        //文章分类上面的滑块
        this.search.coverTop = this.$route.params.id -0;
      },
      coverAnimEnter(index){
        //滑块位置
        this.search.coverTop = index
      },
      windowScroll(){
        //滚动 分类的动画
        this.search.ifSearchSuspension = document.documentElement.scrollTop >=950
      },
      //搜索框输入内容
      handInput(){
        if (this.search.searchInput) {
          clearTimeout(this.search.t);
          this.search.t = setTimeout(t=>{
            let key = this.search.searchInput.trim();
            if (key) {
              getSearch({value:key})
                .then(data=>{
                  this.search.searchList = data.data.data;
                  if(!data.data.data.length){
                    this.$message({type: 'warning',message:"没有你查的值哦"})
                  }
                })
            }
          },500);
        }else{
          this.search.searchList = []
        }
      }
    },
    created() {
      //生命周期 检测数据之后
      //文章分类请求
      getArticleInfo()
        .then(res=>{
          this.search.tags = res.data.data.tags;
        });
      //热门文章请求
      getArticlePopular()
        .then(res=>{
          this.hot = res.data.data
        });
      //最近访客请求
      getVisitor()
        .then(data=>{
          this.visitor = data.data.data;
        })
    },
    mounted() {
      //生命周期实例创建之后
      //监听滚轮事件
      this.windowScroll();
      window.addEventListener("scroll",this.windowScroll)
    },
    destroyed() {
      //生命周期 组件销毁之后
      window.removeEventListener("scroll",this.windowScroll)
    }
  }
</script>

<style scoped lang="less">
  #Container{
    padding-top: 80px;
    min-width: 1064px;
    user-select: none;
    >.el-container{
      box-sizing: border-box;
      width: 100%;
      max-width: 1260px;
      margin: 0 auto;
      padding: 0 50px;
      >.el-main{
        padding-left: 0;
        padding-top: 0;
      }
      >.el-aside{
        width: 300px;
        margin-right: 50px;
        >.search{
          width: 100%;
          background-color: #ffffffcf;
          padding-bottom: 20px;
          border-radius: 15px;
          box-shadow: 0 0 5px #fff;
          &.suspension{
            position: fixed;
            z-index: 3;
            width: 300px;
            animation: searchMove .5s 1 ease-in-out;
            animation-fill-mode: forwards;
          }
          @keyframes searchMove{
            0%{top : -500px}
            40%{top: 91px}
            65%{top: 70px}
            100%{top: 81px}
          }
          .search-main{
            position: relative;
            box-sizing: border-box;
            width: 100%;
            height: 80px;
            padding: 20px;
            border-radius: 10px 10px 0 0;
            background: linear-gradient(to bottom right,rgba(41,48,102),rgba(169,166,211));
            z-index: 3;
            input{
              box-sizing: border-box;
              width: 100%;
              height: 40px;
              padding: 20px;
              border: 0;
              border-radius: 20px;
              outline: 0;
            }
            i{
              position: absolute;
              right: 30px;
              top: 29px;
              width: 22px;
              height: 22px;
              font-size: 18px;
              line-height: 22px;
              text-align: right;
              font-weight: bolder;
              color: rgb(120,121,120);
              background-color: #fff;
              cursor: pointer;
            }
            ul{
              position: absolute;
              width: 260px;
              background-color: #fff;
              top: 50px;
              padding-top: 23px;
              border-radius:5px 5px 10px 10px;
              box-shadow: 0 0 0 #999;
              li{
                overflow: hidden;
                box-sizing: border-box;
                width: 100%;
                height: 40px;
                line-height: 30px;
                padding: 5px;
                a{
                  display: block;
                  width: 100%;
                  height: 100%;
                  color: #474747;
                  &:hover{
                    background-color: #ddd;
                  }
                }
                &:nth-child(1){
                  a{color: red;}
                }
                &:nth-child(2){
                  a{color: green;}
                }
                &:nth-child(3){
                  a{color: #ffdb00;}
                }
              }
            }
          }
          .search-article{
            position: relative;
            width: 100%;
            margin-top: 20px;
            ul{
              width: 100%;
              li{
                position: relative;
                box-sizing: border-box;
                z-index: 1;
                width: 100%;
                height: 40px;
                line-height: 40px;
                padding: 0 30px;
                a{
                  display: block;
                  width: 100%;
                  height: 100%;
                  color: #787977;
                  border-bottom: 1px solid #eee;
                }
              }
            }
            .cover{
              box-sizing: border-box;
              position: absolute;
              top: 0;
              left: 0;
              width: 100%;
              height: 40px;
              border-right: 5px solid #000;
              background-color: rgba(0,0,0,.08);
              transition: top .3s;
            }
          }
        }
        >.hot,.recommend {
          box-sizing: border-box;
          width: 100%;
          margin-top: 20px;
          background-color: #ffffffcf;
          border-radius: 15px;
          box-shadow: 1px 1px 7px #fff;
          padding: 15px 20px 20px;
          h3 {
            padding: 0 5px 10px;
            line-height: 30px;
            font-weight: 400;
            border-bottom: 1px solid #e8e9e7;
            color: #383937;
            position: relative;
            font-size: 18px;
          }
          ul{
            li{
              overflow: hidden;
              white-space:nowrap;
              text-overflow:ellipsis;
              height: 30px;
              line-height: 30px;
              margin: 7px 0;
              a{
                color: #787977;
                font-size: 14px;
                text-decoration: none;
                &:hover{
                  color: #6bc30d;
                  text-decoration: underline;
                }
              }
              i{
                display: inline-block;
                width: 22px;
                height: 22px;
                margin-right: 10px;
                font-style: normal;
                font-size: 12px;
                color: #666;
                line-height: 22px;
                text-align: center;
                border-radius: 100%;
                background-color: #edefee;
                text-shadow: 0 1px 0 rgba(255,255,255,.5);
              }
              &:nth-child(1) i{
                background-color: #e20039;
                color: #fff;
              }
              &:nth-child(2) i{
                background-color: #36cae0;
                color: #fff;
              }
              &:nth-child(3) i{
                background-color: #ffdb00;
                color: #fff;
              }
            }
          }
        }
        >.visitor{
          box-sizing: border-box;
          width: 100%;
          margin-top: 20px;
          background-color: #fff;
          padding: 15px 20px 20px;
          h3{
            padding: 0 5px 10px;
            line-height: 30px;
            font-weight: 400;
            border-bottom: 1px solid #e8e9e7;
            color: #383937;
            position: relative;
            font-size: 18px;
          }
          ul{
            margin-top: 10px;
            li{
              position: relative;
              float: left;
              width: 23%;
              height: 60px;
              margin: 1%;
              background-position: center top;
              background-size: cover;
              background-repeat: no-repeat;
              cursor: pointer;
              p{
                overflow: hidden;
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 20px;
                line-height: 20px;
                text-align: center;
                background-color: rgba(0,0,0,.3);
                white-space:nowrap;
                text-overflow:ellipsis;
                color: #fff;
                font-size: 12px;
              }
            }
            &::after{
              display: block;
              content: '';
              width: 0;
              height: 0;
              clear: both;
            }
          }
        }
      }
    }
  }
</style>