<template>
<!--  博客内容展示-->
  <div class="articleShow">
    <section v-for="(item,index) in article.articleList" :key="item._id">
    <router-link :to="'/article/'+item._id">
      <!--      标题-->
      <h5>
        <span>【{{item.type}}】</span>
        <b>{{item.title}}</b>
      </h5>
      <!--      时间-->
      <div class="time">
        <p class="date">{{item.date | date}}</p>
        <p class="month">{{item.date | month}}<span>月</span></p>
        <p class="year">{{item.date | year}}</p>
      </div>
      <!--      内容-->
      <div class="content">
        <i :style="{backgroundImage:'url('+item.surface+')'}"></i>
        {{item.outline}}
      </div>
      <div class="read-more">
        <i></i>
      </div>
      <div class="footer">
        <div class="fl">
          <i class="el-icon-s-promotion"></i>
          <span>{{item.tag}}</span>
        </div>
        <div class="fr">
          <span class="pv">
            <i class="el-icon-view"></i>
            <i>{{item.pv}}</i>
          </span>
        </div>
      </div>
    </router-link>
    </section>
    <div v-if="article.loading" class="loading">
<!--      http://localhost:3000-->
      <img src="http://dbclick.网址/img/loading.gif" alt="加载中">
    </div>
    <el-divider v-if="article.end" class="no-more">哦豁(⊙o⊙)貌似没有更多内容了</el-divider>
  </div>
</template>

<script>
  //axios
  import axiosApi from '../api';
  let getArticleNew = axiosApi.getArticleNew,//获取最新文章
      getArticleInfo = axiosApi.getArticleInfo;//获取标签

  export default {
    name: "ArticleShow",
    components:{},
    data(){
      return {
        article:{
          articleList:[],
          articleInfoList:[],
          end:false,
          loading:false
        }
      }
    },
    filters : {
      date(value){
        return new Date(value).getDate();
      },
      month(value){
        return new Date(value).getMonth() +1;
      },
      year(value){
        return new Date(value).getFullYear();
      }
    },
    computed:{
      id(){
        return this.$route.params.id
      }
    },
    watch:{
      //监听数据发生变化
      id(){
        document.documentElement.scrollTop = 0;
        this.getArticleShowFresh()
      }
    },
    methods:{
      getArticleShowFresh(){
        getArticleInfo()
          .then(d=>{
            //获取最新文章
            this.article.end = this.article.loading = false;
            this.article.articleInfoList = ["",...d.data.data.tags];
            getArticleNew(this.article.articleInfoList[this.id],true).then(res=>{
              document.documentElement.scrollTop = 0;
              this.article.articleList = res.data.data;
              if (!res.data.data.length || res.data.data.length < 5) {
                this.article.end = true
              }
            });
          })
          .catch();
      },
      articleScroll(){
        //滚轮加载
        if(this.article.end || this.article.loading) return;

        let allHeight = document.documentElement.offsetHeight,//文章的全部高
            scrollHeight = document.documentElement.scrollTop,//滚动高
            winHeight = document.documentElement.clientHeight;//可视区高
        if (scrollHeight + winHeight > allHeight - 100) {
          this.article.loading = true;
          getArticleNew(this.article.articleInfoList[this.id])
            .then(res=>{
              this.article.loading = false;
              let data = res.data.data;
              if(data.length){
                this.article.articleList.push(...data);
              }else{
                //没有更多数据了
                this.article.end = true
              }
            });
        }
      }
    },
    mounted() {
      //生命周期 组件生成之后
      //获取最新文章接口
      this.getArticleShowFresh();
    //  滚轮获取文章
      window.addEventListener("scroll",this.articleScroll);
    }
  }
</script>

<style scoped lang="less">
  .articleShow{
    >section{
      overflow: hidden;
      position: relative;
      box-sizing: border-box;
      width: 100%;
      padding: 20px 30px 25px;
      margin-bottom: 20px;
      background-color: #fff;
      border-radius: 23px;
      box-shadow: 0 0 6px #fff;
      animation: show .7s 1;
      animation-fill-mode: forwards;
      @keyframes show{
        from{opacity: .5;transform: translateX(-300px)}
        to{opacity: 1;transform: translateX(0)}
      }
      &:nth-child(1)::before{
        content: "New";
        position: absolute;
        height: 20px;
        line-height: 20px;
        text-align: center;
        width: 74px;
        background-color: #67C23A;
        color: #fff;
        transform: rotate(-45deg);
        left: -18px;
        top: 9px;
      }
      a{
        >h5{
          line-height: 30px;
          padding: 5px 130px 5px 0;
          border-bottom: 1px solid #e8e9e7;
          font-size: 18px;
          font-weight: 400;
          span{
            font-size: 16px;
            font-weight: 400;
            display: inline-block;
            vertical-align: bottom;
            color: #2ea7e0;
          }
          b{
            font-weight: 100;
            color: #000;
            text-decoration: none;
            transition: .5s;
            &:hover{
              color: #1556c3;
            }
          }
        }
        .time{
          width: 90px;
          height: 70px;
          font-family: SourceCodeProRegular,Menlo,Monaco,Consolas,"Courier New",monospace,'Helvetica Neue',Arial,sans-serif;
          position: absolute;
          right: 10px;
          top: 10px;
          background-color: #fff;
          padding: 0 20px 5px 20px;
          line-height: 32px;
          .date{
            display: block;
            text-align: center;
            font-weight: 700;
            font-size: 40px;
            color: #6bc30d;
            position: relative;
            top: 2px;
          }
          .month{
            display: inline-block;
            color: #989997;
            font-size: 18px;
            span{
              font-size: 14px;
            }
          }
          .year{
            display: inline-block;
            color: #989997;
            margin-left: 10px;
            font-size: 18px;
          }
        }
        .content{
          margin-top: 20px;
          line-height: 28px;
          position: relative;
          min-height: 200px;
          color: #000;
          i{
            position: relative;
            display: block;
            overflow: hidden;
            float: left;
            width: 300px;
            height: 180px;
            border: 1px solid #e8e9e7;
            margin-right: 20px;
            background-image: url("../assets/img/login.gif");
            background-position: center;
            background-size: cover;
          }
        }
        .read-more{
          position: relative;
          &::before{
            content: " ";
            display: inline-block;
            height: 1px;
            top: 20px;
            left: 100px;
            right: 0;
            position: absolute;
            background-color: #d0d0d0;
          }
          i{
            font-weight: bold;
            color: #383937;
            text-decoration: none;
            border: none;
            line-height: 40px;
            &:hover{
              color: #00b9c3;
              text-decoration: underline;
            }
          }
        }
        .footer{
          .fl{
            float: left;
            i{
              font-size: 18px;
              margin-right: 5px;
              color: #666;
            }
            span{
              display: inline-block;
              font-size: 12px;
              padding: 2px 5px;
              background-color: #f1f2f0;
              color: #787977;
              margin: 2px;
              text-decoration: none;
              -webkit-transition: all .2s;
              transition: all .2s;
              &:hover{
                color: #fff;
                background: #B42533;
              }
            }
          }
          .fr{
            float: right;
            color: #666;
            i{
              font-style: normal;
              margin-right: 12px;
            }
          }
        }
      }
    }
    >.loading{
      position: relative;
      background-color: #1f2123;
      text-align: center;
      >img {
        width: 110px;
        height: 60px;
      }
    }
    >.no-more{
      text-align: center;
      background-color: #fff;
      font-size: 12px;
      >div{
        background-color: #AEB0D6;
      }
    }
  }
</style>